import fs from "node:fs";
import { afterAll, beforeEach, describe, expect, it, vi } from "vitest";
const { TMP_HOME } = vi.hoisted(() => {
    const nodeOs = require("node:os");
    const nodePath = require("node:path");
    return {
        TMP_HOME: nodePath.join(nodeOs.tmpdir(), `bitfab-eventlog-test-${Date.now()}-${Math.random().toString(36).slice(2)}`),
    };
});
vi.mock("node:os", async (importActual) => {
    const actual = await importActual();
    return {
        ...actual,
        default: { ...actual, homedir: () => TMP_HOME },
        homedir: () => TMP_HOME,
    };
});
import { appendStudioEvent, eventLogPathForKey, readStudioEventLogTail, studioEventToLogLine, tailStudioEvents, truncateStudioEventLog, } from "./studioEventLog.js";
const KEY = "agent-session-abc";
beforeEach(() => {
    truncateStudioEventLog(KEY);
});
afterAll(() => {
    fs.rmSync(TMP_HOME, { recursive: true, force: true });
});
describe("studioEventToLogLine", () => {
    it("strips the studio: prefix and keeps the routed fields", () => {
        const event = {
            id: "1",
            type: "studio:edit-with-agent",
            data: { datasetId: "ds_1" },
        };
        expect(studioEventToLogLine(event, "sess_1")).toEqual({
            event: "edit-with-agent",
            sessionId: "sess_1",
            datasetId: "ds_1",
        });
    });
    it("carries navigated path and search", () => {
        const event = {
            id: "2",
            type: "studio:navigated",
            data: { path: "/studio/x", search: "?trace=1" },
        };
        expect(studioEventToLogLine(event, "sess_1")).toEqual({
            event: "navigated",
            sessionId: "sess_1",
            path: "/studio/x",
            search: "?trace=1",
        });
    });
    it("never writes the auth token to the log line", () => {
        const event = {
            id: "3",
            type: "studio:authenticated",
            data: { token: "secret-token" },
        };
        const line = studioEventToLogLine(event, "sess_1");
        expect(line).toEqual({ event: "authenticated", sessionId: "sess_1" });
        expect(JSON.stringify(line)).not.toContain("secret-token");
    });
    it("carries all data fields (so every consumer reads the one bus)", () => {
        const event = {
            id: "4",
            type: "tracePlan:confirmed",
            data: { planId: "p_1", traceFunctionKey: "fn" },
        };
        expect(studioEventToLogLine(event, "sess_1")).toEqual({
            event: "tracePlan:confirmed",
            sessionId: "sess_1",
            planId: "p_1",
            traceFunctionKey: "fn",
        });
    });
    it("excludes the token even when other fields are present", () => {
        const event = {
            id: "5",
            type: "studio:element-clicked",
            data: { traceId: "t_1", fieldPath: "a.b", token: "secret" },
        };
        const line = studioEventToLogLine(event, "sess_1");
        expect(line).toEqual({
            event: "element-clicked",
            sessionId: "sess_1",
            traceId: "t_1",
            fieldPath: "a.b",
        });
        expect(JSON.stringify(line)).not.toContain("secret");
    });
});
describe("tailStudioEvents", () => {
    it("delivers each appended line until aborted", async () => {
        const ac = new AbortController();
        const seen = [];
        const done = tailStudioEvents(KEY, (line) => {
            seen.push(line);
            if (line.event === "session-ended") {
                ac.abort();
            }
        }, { abortSignal: ac.signal, pollMs: 5 });
        appendStudioEvent(KEY, { event: "started" });
        appendStudioEvent(KEY, { event: "edit-with-agent", datasetId: "d" });
        await new Promise((r) => setTimeout(r, 20));
        appendStudioEvent(KEY, { event: "session-ended" });
        await done;
        expect(seen.map((l) => l.event)).toEqual([
            "started",
            "edit-with-agent",
            "session-ended",
        ]);
    });
    it("delivers no line once aborted", async () => {
        const ac = new AbortController();
        ac.abort();
        const seen = [];
        appendStudioEvent(KEY, { event: "started" });
        await tailStudioEvents(KEY, (l) => seen.push(l), {
            abortSignal: ac.signal,
            pollMs: 5,
        });
        expect(seen).toEqual([]);
    });
    it("resumes from a cursor", async () => {
        appendStudioEvent(KEY, { event: "a" });
        appendStudioEvent(KEY, { event: "b" });
        const ac = new AbortController();
        const seen = [];
        const done = tailStudioEvents(KEY, (l) => seen.push(l), {
            fromLine: 2,
            abortSignal: ac.signal,
            pollMs: 5,
        });
        await new Promise((r) => setTimeout(r, 15));
        ac.abort();
        await done;
        expect(seen.map((l) => l.event)).toEqual(["b"]);
    });
});
describe("append / read tail", () => {
    it("appends JSONL lines and reads them back from a cursor", () => {
        appendStudioEvent(KEY, { event: "started", sessionId: "s" });
        appendStudioEvent(KEY, { event: "edit-with-agent", datasetId: "ds" });
        appendStudioEvent(KEY, { event: "session-ended" });
        const all = readStudioEventLogTail(KEY);
        expect(all.lines).toHaveLength(3);
        expect(all.nextLine).toBe(4);
        expect(all.lines[1]).toEqual({ event: "edit-with-agent", datasetId: "ds" });
        const tail = readStudioEventLogTail(KEY, all.nextLine);
        expect(tail.lines).toHaveLength(0);
        expect(tail.nextLine).toBe(4);
        appendStudioEvent(KEY, { event: "saved" });
        const resumed = readStudioEventLogTail(KEY, all.nextLine);
        expect(resumed.lines).toEqual([{ event: "saved" }]);
        expect(resumed.nextLine).toBe(5);
    });
    it("reads from a mid-stream offset", () => {
        appendStudioEvent(KEY, { event: "a" });
        appendStudioEvent(KEY, { event: "b" });
        appendStudioEvent(KEY, { event: "c" });
        const tail = readStudioEventLogTail(KEY, 2);
        expect(tail.lines).toEqual([{ event: "b" }, { event: "c" }]);
    });
    it("returns empty for a missing log", () => {
        const res = readStudioEventLogTail("never-written");
        expect(res.lines).toEqual([]);
        expect(res.nextLine).toBe(1);
    });
});
describe("truncate", () => {
    it("removes the log so a fresh session starts clean", () => {
        appendStudioEvent(KEY, { event: "started" });
        expect(fs.existsSync(eventLogPathForKey(KEY))).toBe(true);
        truncateStudioEventLog(KEY);
        expect(fs.existsSync(eventLogPathForKey(KEY))).toBe(false);
        expect(readStudioEventLogTail(KEY).lines).toEqual([]);
    });
    it("keyed logs are isolated from each other", () => {
        appendStudioEvent("key-a", { event: "a" });
        appendStudioEvent("key-b", { event: "b" });
        expect(readStudioEventLogTail("key-a").lines).toEqual([{ event: "a" }]);
        expect(readStudioEventLogTail("key-b").lines).toEqual([{ event: "b" }]);
        truncateStudioEventLog("key-a");
        truncateStudioEventLog("key-b");
    });
});
